"use client";

/**
 * COLD-TEST screen: a documentation-site HOME / overview page for a fictional
 * typed HTTP client called "Driftwood", built entirely on @gunjo/ui@0.0.1-alpha.2
 * (installed package + https://gunjo.jp docs only — the private monorepo was never
 * read). The actual deliverable is the friction report; per-component notes live
 * next to the code that hit them (SidebarNav / OnThisPage / TopBar).
 *
 * TOP-LEVEL FRICTION SUMMARY (full list in the report):
 *  - NO typography / Prose / Heading primitive. Every <h1>/<h2>/<h3>/<p>/<ul> in
 *    the doc body below is hand-rolled raw HTML + Tailwind. This is the single
 *    biggest gap for a docs home (the body is ~70% long-form prose).
 *  - NO table-of-contents primitive (see OnThisPage.tsx).
 *  - DocNote has only `default | reference` variants — NO note/warning/tip/info
 *    semantic callouts, no icons, no role color. I fake the three admonition
 *    flavors by layering my own border/icon on top of DocNote (see Callout).
 *  - DocsTemplate exists but its grid is `grid-cols-[200px_1fr]` at the BASE
 *    breakpoint — the left column is a hard 200px even at 375px and never
 *    collapses to a drawer. So I do NOT use DocsTemplate; I build the responsive
 *    shell myself (sidebar `hidden lg:block`, drawer on mobile via TopBar).
 */

import * as React from "react";
import {
  Grid,
  Card,
  CardHeader,
  CardDescription,
  CardContent,
  Badge,
  Button,
  CodeBlock,
  Code,
  DocNote,
  TextLink,
  DocumentPager,
  Breadcrumb,
  BreadcrumbList,
  BreadcrumbItem,
  BreadcrumbLink,
  BreadcrumbPage,
  BreadcrumbSeparator,
  Footer,
  FooterColumns,
  FooterSection,
  FooterLink,
  FooterBrand,
  FooterCopyright,
  cn,
} from "@gunjo/ui";
import {
  IconRocket,
  IconPuzzle,
  IconApi,
  IconInfoCircle,
  IconAlertTriangle,
  IconBulb,
  IconArrowRight,
} from "@tabler/icons-react";
import { TopBar, paletteIcons } from "./TopBar";
import { SidebarNav } from "./SidebarNav";
import { OnThisPage } from "./OnThisPage";
import { componentIndex } from "./nav-data";

const INSTALL_CMD = `npm install driftwood
# or
pnpm add driftwood`;

const USAGE_SNIPPET = `import { createClient } from "driftwood";

const api = createClient({
  baseUrl: "https://api.example.com",
  headers: { Authorization: \`Bearer \${token}\` },
});

const user = await api.get("/users/42").json<User>();`;

const REQUEST_SNIPPET = `// POST with a typed body + automatic retry
const created = await api
  .post("/posts", { json: { title: "Hello" } })
  .retry({ limit: 3 })
  .json<Post>();`;

const commandGroups = [
  {
    heading: "はじめに",
    items: [
      { id: "intro", label: "概要", icon: paletteIcons.book, action: () => jump("introduction") },
      { id: "install", label: "インストール", icon: paletteIcons.download, action: () => jump("installation") },
      { id: "quick", label: "クイックスタート", icon: paletteIcons.rocket, action: () => jump("quick-start") },
    ],
  },
];

function jump(id: string) {
  document.getElementById(id)?.scrollIntoView({ behavior: "smooth" });
}

export default function DocsHomePage() {
  return (
    <div className="flex min-h-screen flex-col bg-background text-foreground">
      <TopBar commandGroups={commandGroups} />

      <div className="mx-auto flex w-full max-w-screen-2xl flex-1">
        {/* Left sidebar — real nav, sticky, full-height, hidden on mobile (drawer instead) */}
        <aside className="sticky top-[57px] hidden h-[calc(100vh-57px)] w-64 shrink-0 overflow-y-auto border-r border-border px-4 py-6 lg:block">
          <SidebarNav />
        </aside>

        {/*
          Content + right-rail TOC.
          FRICTION (Minor, component-bug): I first used `PageAside` (the closest
          thing to a docs "content + On-this-page" shell). It renders the mobile
          version of the aside through `AccordionTrigger`, which wraps the title
          in a Radix <h3> — so even a plain-string title becomes an <h3> in the
          outline, AND because that mobile aside is `lg:hidden` (display:none on
          desktop) it still sits in the DOM as the FIRST heading on the page,
          before the <h1>. There's no prop to opt out of the heading or the mobile
          accordion. So I hand-build the responsive TOC shell to keep the heading
          outline clean (right rail on xl, a <details> disclosure below that).
        */}
        <div className="flex min-w-0 flex-1 flex-col xl:flex-row">
          <div className="min-w-0 flex-1">
            <article className="mx-auto w-full max-w-3xl px-4 py-8 sm:px-8">
              <Breadcrumb className="mb-6">
                <BreadcrumbList>
                  <BreadcrumbItem>
                    <BreadcrumbLink href="#">ドキュメント</BreadcrumbLink>
                  </BreadcrumbItem>
                  <BreadcrumbSeparator />
                  <BreadcrumbItem>
                    <BreadcrumbLink href="#">はじめに</BreadcrumbLink>
                  </BreadcrumbItem>
                  <BreadcrumbSeparator />
                  <BreadcrumbItem>
                    <BreadcrumbPage>概要</BreadcrumbPage>
                  </BreadcrumbItem>
                </BreadcrumbList>
              </Breadcrumb>

              {/* ---- Doc body. Every heading/paragraph is hand-rolled HTML. ---- */}
              <header className="mb-8">
                <Badge variant="secondary" className="mb-3">
                  v2.0
                </Badge>
                <h1
                  id="introduction"
                  className="scroll-mt-24 text-3xl font-bold tracking-tight sm:text-4xl"
                >
                  概要
                </h1>
                <p className="mt-4 text-lg leading-relaxed text-muted-foreground">
                  Driftwoodは、TypeScript向けの小さくて完全に型付けされたHTTPクライアントです。{" "}
                  <Code>fetch</Code> を、流暢でチェーン可能なAPIでラップ。型付きレスポンス、
                  組み込みのリトライ、インターセプター、そしてランタイム依存ゼロを実現します。
                </p>
              </header>

              {/* Cards row */}
              <Grid minItemWidth={200} gap={4} className="mb-10">
                <ActionCard
                  icon={<IconRocket className="h-5 w-5" />}
                  title="まず始める"
                  description="インストールして、1分以内に最初のリクエストを送りましょう。"
                  cta="クイックスタート"
                  href="#quick-start"
                />
                <ActionCard
                  icon={<IconPuzzle className="h-5 w-5" />}
                  title="コンポーネントを見る"
                  description="Client、Request、Response、Interceptors、Hooks。"
                  cta="コンポーネント"
                  href="#components"
                />
                <ActionCard
                  icon={<IconApi className="h-5 w-5" />}
                  title="APIリファレンス"
                  description="すべてのメソッド・オプション・型を、余すことなく解説。"
                  cta="リファレンス"
                  href="#"
                />
              </Grid>

              {/* Installation */}
              <Section id="installation" title="インストール">
                <p className="mb-4 leading-relaxed text-muted-foreground">
                  DriftwoodはESM + CJSで提供され、Node 18以降、または{" "}
                  <Code>fetch</Code> をサポートするモダンブラウザで動作します。
                </p>
                <CodeBlock
                  code={INSTALL_CMD}
                  language="bash"
                  filename="ターミナル"
                  theme="dark"
                  className="mb-4"
                />
                <Callout variant="note">
                  Driftwoodのランタイム依存は<strong>ゼロ</strong>。インストールサイズはわずか数キロバイトです。
                </Callout>
              </Section>

              {/* Quick Start */}
              <Section id="quick-start" title="クイックスタート">
                <p className="mb-5 leading-relaxed text-muted-foreground">
                  クライアントを一度作成すれば、どこからでも型付きのリクエストを発行できます。
                </p>

                <h3
                  id="create-a-client"
                  className="scroll-mt-24 mb-3 mt-6 text-lg font-semibold tracking-tight"
                >
                  クライアントを作成する
                </h3>
                <CodeBlock
                  code={USAGE_SNIPPET}
                  language="ts"
                  filename="api.ts"
                  theme="dark"
                  highlight
                  showLineNumbers
                  className="mb-6"
                />

                <h3
                  id="make-a-request"
                  className="scroll-mt-24 mb-3 mt-6 text-lg font-semibold tracking-tight"
                >
                  リクエストを送る
                </h3>
                <CodeBlock
                  code={REQUEST_SNIPPET}
                  language="ts"
                  filename="create-post.ts"
                  theme="dark"
                  highlight
                  className="mb-4"
                />
                <Callout variant="warning">
                  <Code>retry.limit</Code> を設定するのは、冪等なリクエストだけにしてください。冪等でない{" "}
                  <Code>POST</Code> をリトライすると、書き込みが二重に発生するおそれがあります。
                </Callout>
                <Callout variant="tip">
                  認証ヘッダーをリクエストごとに付けるのではなく、{" "}
                  <TextLink href="#">インターセプター</TextLink>{" "}
                  を使って全体に一括で付与しましょう。
                </Callout>
              </Section>

              {/* Features */}
              <Section id="features" title="主な機能">
                <ul className="grid gap-2 sm:grid-cols-2">
                  {[
                    "`.json<T>()` によるエンドツーエンドの型付きレスポンス",
                    "バックオフ付きの自動・設定可能なリトライ",
                    "リクエスト／レスポンスのインターセプター",
                    "リクエストごとのタイムアウトとキャンセル",
                    "ストリーミングレスポンス（Beta）",
                    "ランタイム依存ゼロ",
                  ].map((f) => (
                    <li key={f} className="flex items-start gap-2 text-sm">
                      <IconArrowRight className="mt-0.5 h-4 w-4 shrink-0 text-primary" />
                      <span className="text-muted-foreground">{f}</span>
                    </li>
                  ))}
                </ul>
              </Section>

              {/* Component index */}
              <Section id="components" title="コンポーネント一覧">
                <p className="mb-4 leading-relaxed text-muted-foreground">
                  Driftwood APIを構成する、中心的な部品たちです。
                </p>
                <Grid minItemWidth={160} gap={3}>
                  {componentIndex.map((c) => (
                    <a
                      key={c.label}
                      href={c.href}
                      className="group flex items-center justify-between rounded-md border border-border bg-card px-3 py-2.5 text-sm font-medium transition-colors hover:border-primary-border hover:bg-muted/40"
                    >
                      <span>{c.label}</span>
                      {c.badge ? (
                        <Badge variant="outline" className="h-4 px-1.5 text-[10px]">
                          {c.badge}
                        </Badge>
                      ) : (
                        <IconArrowRight className="h-4 w-4 text-muted-foreground transition-transform group-hover:translate-x-0.5" />
                      )}
                    </a>
                  ))}
                </Grid>
              </Section>

              {/* Prev / Next */}
              <div className="mt-12">
                <DocumentPager
                  previous={{
                    href: "#",
                    directionLabel: "前へ",
                    title: "概要",
                  }}
                  next={{
                    href: "#installation",
                    directionLabel: "次へ",
                    title: "インストール",
                    description: "Driftwoodをプロジェクトに追加します。",
                  }}
                />
              </div>

              {/* Mobile "On this page" — below the content, real disclosure, no injected heading */}
              <details className="mt-10 rounded-md border border-border bg-muted/30 p-3 xl:hidden">
                <summary className="cursor-pointer list-none text-xs font-semibold uppercase tracking-wide text-muted-foreground">
                  このページの内容
                </summary>
                <div className="mt-3">
                  <OnThisPage />
                </div>
              </details>
            </article>
          </div>

          {/* Right-rail TOC — desktop only, sticky, full height */}
          <aside className="sticky top-[57px] hidden h-[calc(100vh-57px)] w-60 shrink-0 overflow-y-auto px-6 py-8 xl:block">
            <OnThisPage />
          </aside>
        </div>
      </div>

      <SiteFooter />
    </div>
  );
}

/* ------------------------------------------------------------------ *
 * Hand-rolled doc-body helpers (no gunjo primitive covers these).
 * ------------------------------------------------------------------ */

/** A doc section = an anchored <h2> + body. There is no Heading/Section in gunjo. */
function Section({
  id,
  title,
  children,
}: {
  id: string;
  title: string;
  children: React.ReactNode;
}) {
  return (
    <section className="mb-10">
      <h2
        id={id}
        className="scroll-mt-24 mb-4 border-b border-border pb-2 text-2xl font-semibold tracking-tight"
      >
        {title}
      </h2>
      {children}
    </section>
  );
}

/**
 * Admonition callout. DocNote ships only `default | reference` (no semantics),
 * so the note/warning/tip flavors are produced by layering an accent border +
 * icon on top of DocNote. This is the workaround for the missing variant set.
 */
function Callout({
  variant,
  children,
}: {
  variant: "note" | "warning" | "tip";
  children: React.ReactNode;
}) {
  const map = {
    note: {
      icon: <IconInfoCircle className="h-4 w-4" />,
      label: "メモ",
      cls: "border-l-info text-foreground [&_a]:text-info",
      tint: "bg-info-subtle/40",
    },
    warning: {
      icon: <IconAlertTriangle className="h-4 w-4" />,
      label: "注意",
      cls: "border-l-warning text-foreground",
      tint: "bg-warning-subtle/40",
    },
    tip: {
      icon: <IconBulb className="h-4 w-4" />,
      label: "ヒント",
      cls: "border-l-success text-foreground",
      tint: "bg-success-subtle/40",
    },
  }[variant];

  return (
    <DocNote
      heading={
        <span className="flex items-center gap-1.5">
          {map.icon}
          {map.label}
        </span>
      }
      className={cn("my-4 border-l-4", map.cls, map.tint)}
    >
      <span className="text-muted-foreground">{children}</span>
    </DocNote>
  );
}

function ActionCard({
  icon,
  title,
  description,
  cta,
  href,
}: {
  icon: React.ReactNode;
  title: string;
  description: string;
  cta: string;
  href: string;
}) {
  return (
    <Card className="transition-colors hover:border-primary-border">
      <CardHeader className="gap-2 p-5">
        <div className="grid h-9 w-9 place-items-center rounded-md bg-primary-subtle text-primary">
          {icon}
        </div>
        {/*
          NOTE (a11y/finding): CardTitle renders a hard-coded <h3> with no `as`
          / `level` prop. Using it here injected <h3>s right after the page <h1>,
          producing a WCAG heading-order skip (1 -> 3). These cards are not
          document headings, so render a styled non-heading element instead.
        */}
        <p className="text-base font-semibold leading-none tracking-tight">{title}</p>
        <CardDescription>{description}</CardDescription>
      </CardHeader>
      <CardContent className="mt-auto p-5 pt-0">
        <Button asChild variant="outline" size="sm">
          <a href={href}>
            {cta}
            <IconArrowRight className="h-3.5 w-3.5" />
          </a>
        </Button>
      </CardContent>
    </Card>
  );
}

function SiteFooter() {
  return (
    <Footer className="mt-8">
      <FooterColumns>
        <FooterBrand>
          <span className="flex items-center gap-2 font-semibold">
            <IconRocket className="h-4 w-4" /> Driftwood
          </span>
          <p className="text-sm text-muted-foreground">
            TypeScript向けの、小さな型付きHTTPクライアント。
          </p>
        </FooterBrand>
        <FooterSection title="ドキュメント">
          <FooterLink href="#introduction">概要</FooterLink>
          <FooterLink href="#installation">インストール</FooterLink>
          <FooterLink href="#quick-start">クイックスタート</FooterLink>
        </FooterSection>
        <FooterSection title="コミュニティ">
          <FooterLink href="#">GitHub</FooterLink>
          <FooterLink href="#">Discord</FooterLink>
          <FooterLink href="#">ディスカッション</FooterLink>
        </FooterSection>
        <FooterSection title="その他">
          <FooterLink href="#">変更履歴</FooterLink>
          <FooterLink href="#">ブログ</FooterLink>
          <FooterLink href="#">ライセンス</FooterLink>
        </FooterSection>
      </FooterColumns>
      <FooterCopyright>
        © {new Date().getFullYear()} Driftwood. @gunjo/ui で構築。MITライセンス。
      </FooterCopyright>
    </Footer>
  );
}

/**
 * Static IA for the fictional "Driftwood" docs site (a typed HTTP/API client).
 * Plain data so both the desktop sidebar and the mobile drawer render the
 * exact same tree (single source for the nav).
 */

export interface NavLink {
  label: string;
  href: string;
  /** Optional trailing badge text, e.g. "New" / "Beta". */
  badge?: string;
}

export interface NavGroup {
  heading: string;
  items: NavLink[];
}

/** Left-sidebar groups. */
export const sidebarGroups: NavGroup[] = [
  {
    heading: "はじめに",
    items: [
      { label: "概要", href: "#introduction" },
      { label: "インストール", href: "#installation" },
      { label: "クイックスタート", href: "#quick-start" },
    ],
  },
  {
    heading: "ガイド",
    items: [
      { label: "認証", href: "#" },
      { label: "エラーハンドリング", href: "#" },
      { label: "リトライとタイムアウト", href: "#" },
      { label: "ストリーミング", href: "#", badge: "Beta" },
    ],
  },
  {
    heading: "コンポーネント",
    items: [
      { label: "Client", href: "#" },
      { label: "Request", href: "#" },
      { label: "Response", href: "#" },
      { label: "Interceptors", href: "#" },
      { label: "Hooks", href: "#", badge: "New" },
    ],
  },
];

/** The single active doc page in this demo. */
export const activeHref = "#introduction";

/** Top doc-nav bar links. */
export const topNav: NavLink[] = [
  { label: "ドキュメント", href: "#" },
  { label: "コンポーネント", href: "#" },
  { label: "API", href: "#" },
  { label: "ブログ", href: "#" },
];

/** "On this page" entries — drives both the right rail TOC and scroll spy. */
export interface TocEntry {
  id: string;
  label: string;
  level: 2 | 3;
}

export const tocEntries: TocEntry[] = [
  { id: "introduction", label: "概要", level: 2 },
  { id: "installation", label: "インストール", level: 2 },
  { id: "quick-start", label: "クイックスタート", level: 2 },
  { id: "create-a-client", label: "クライアントを作成する", level: 3 },
  { id: "make-a-request", label: "リクエストを送る", level: 3 },
  { id: "features", label: "主な機能", level: 2 },
  { id: "components", label: "コンポーネント一覧", level: 2 },
];

/** Component-index grid links. */
export const componentIndex: NavLink[] = [
  { label: "Client", href: "#" },
  { label: "Request", href: "#" },
  { label: "Response", href: "#" },
  { label: "Interceptors", href: "#" },
  { label: "Retry Policy", href: "#" },
  { label: "Hooks", href: "#", badge: "New" },
];

"use client";

import * as React from "react";
import { cn } from "@gunjo/ui";
import { tocEntries } from "./nav-data";

/**
 * FRICTION (Major, missing-component): there is NO table-of-contents / "On this
 * page" primitive in @gunjo/ui. Nothing reads the headings, nothing tracks the
 * active section. `PageAside` / `RightRail` are generic *containers* (a right rail
 * + a mobile accordion), so they give you the responsive shell — but the actual
 * TOC list, the anchor links, AND the scroll-spy are all hand-built here.
 * The heading ids the anchors point at are likewise hand-maintained (see nav-data
 * `tocEntries`) because there's no Heading primitive to auto-slug them.
 */
export function OnThisPage() {
  const [activeId, setActiveId] = React.useState<string>(tocEntries[0]?.id ?? "");

  React.useEffect(() => {
    const headings = tocEntries
      .map((e) => document.getElementById(e.id))
      .filter((el): el is HTMLElement => el !== null);
    if (headings.length === 0) return;

    const observer = new IntersectionObserver(
      (entries) => {
        const visible = entries
          .filter((e) => e.isIntersecting)
          .sort((a, b) => a.boundingClientRect.top - b.boundingClientRect.top);
        if (visible[0]) setActiveId(visible[0].target.id);
      },
      // Bias the "active" zone toward the top of the viewport.
      { rootMargin: "0px 0px -70% 0px", threshold: [0, 1] }
    );

    headings.forEach((h) => observer.observe(h));
    return () => observer.disconnect();
  }, []);

  return (
    <nav aria-label="このページの内容" className="text-sm">
      <p className="mb-3 text-xs font-semibold uppercase tracking-wide text-muted-foreground">
        このページの内容
      </p>
      <ul className="flex flex-col gap-1.5 border-l border-border">
        {tocEntries.map((entry) => {
          const active = entry.id === activeId;
          return (
            <li key={entry.id}>
              <a
                href={`#${entry.id}`}
                aria-current={active ? "location" : undefined}
                className={cn(
                  "-ml-px block border-l-2 py-0.5 transition-colors",
                  entry.level === 3 ? "pl-6" : "pl-3",
                  active
                    ? "border-primary font-medium text-foreground"
                    : "border-transparent text-muted-foreground hover:text-foreground"
                )}
              >
                {entry.label}
              </a>
            </li>
          );
        })}
      </ul>
    </nav>
  );
}

"use client";

import * as React from "react";
import { Badge, cn } from "@gunjo/ui";
import { sidebarGroups, activeHref, type NavLink } from "./nav-data";

/**
 * FRICTION (Major, missing-component): @gunjo/ui ships `Sidebar` + `SidebarItem`,
 * but they are built for a *stateful app shell*, not a docs nav:
 *   - `SidebarItem` has NO `href`. Required props are { icon, label, isActive,
 *     onClick, id } and it renders a <button>, not an <a>. A docs sidebar needs
 *     real anchor links (right-click/open-in-new-tab, crawlable, #-anchors).
 *   - `icon` is REQUIRED (`React.ReactNode`, not optional) — docs nav rows are
 *     usually icon-less, so you'd be forced to pass a spacer.
 *   - There is no grouped/section primitive (no `SidebarGroup` / `SidebarSection`
 *     with a heading). `Sidebar` only gives Header/Body/Footer/Separator slots.
 *   - `Sidebar` hard-codes its width to `w-[240px]` / collapsed `w-[60px]` and
 *     requires a `SidebarProvider`; its collapse is an icon-rail toggle, NOT a
 *     mobile drawer.
 * Net: for a real docs tree with section headings + active anchor links I hand-roll
 * a <nav> of <a>s. I reuse Badge for the "New"/"Beta" tags (that part is fine).
 */
export function SidebarNav({
  onNavigate,
  idPrefix = "",
}: {
  /** Called after a link is clicked (used to close the mobile drawer). */
  onNavigate?: () => void;
  /** Disambiguate ids when the tree is rendered twice (desktop + drawer). */
  idPrefix?: string;
}) {
  return (
    <nav aria-label="ドキュメント" className="flex flex-col gap-6">
      {sidebarGroups.map((group) => (
        <div key={group.heading} className="flex flex-col gap-1">
          <p className="px-2 text-xs font-semibold uppercase tracking-wide text-muted-foreground">
            {group.heading}
          </p>
          <ul className="flex flex-col gap-0.5">
            {group.items.map((item) => (
              <SidebarLink
                key={`${idPrefix}${group.heading}-${item.label}`}
                item={item}
                active={item.href === activeHref}
                onNavigate={onNavigate}
              />
            ))}
          </ul>
        </div>
      ))}
    </nav>
  );
}

function SidebarLink({
  item,
  active,
  onNavigate,
}: {
  item: NavLink;
  active: boolean;
  onNavigate?: () => void;
}) {
  return (
    <li>
      <a
        href={item.href}
        onClick={onNavigate}
        aria-current={active ? "page" : undefined}
        className={cn(
          "flex h-8 items-center justify-between gap-2 rounded-md px-2 text-sm transition-colors",
          active
            ? "bg-secondary font-medium text-foreground"
            : "text-muted-foreground hover:bg-muted hover:text-foreground"
        )}
      >
        <span className="truncate">{item.label}</span>
        {item.badge ? (
          <Badge variant="outline" className="h-4 px-1.5 text-[10px]">
            {item.badge}
          </Badge>
        ) : null}
      </a>
    </li>
  );
}

"use client";

import * as React from "react";
import {
  Header,
  HeaderBrand,
  HeaderNav,
  HeaderNavLink,
  HeaderActions,
  SearchInput,
  CommandPalette,
  Kbd,
  Button,
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
  SheetDescription,
  Drawer, // imported only to confirm it exists; Sheet is the chosen drawer
} from "@gunjo/ui";
import {
  IconBrandGithub,
  IconMenu2,
  IconSun,
  IconMoon,
  IconBook,
  IconDownload,
  IconRocket,
} from "@tabler/icons-react";
import { topNav } from "./nav-data";
import { SidebarNav } from "./SidebarNav";

void Drawer; // silence unused — see friction note below

/**
 * Top documentation nav bar.
 *
 * Composed from gunjo's Header family (Header / HeaderBrand / HeaderNav /
 * HeaderNavLink / HeaderActions), SearchInput, CommandPalette, Kbd, Button, Sheet.
 *
 * FRICTION (Minor, missing-component): there is NO responsive/collapsing navbar.
 * Header flex-wraps but ships no hamburger + no disclosure, and `HeaderNav`
 * doesn't hide its links on mobile — so the top links are simply hidden by hand
 * (`hidden md:flex`) and a hand-built <button> opens the sidebar Sheet on mobile.
 *
 * FRICTION (Minor, missing-component): there's no theme-toggle component and no
 * ThemeProvider in the package surface (next-themes is an internal dep but not
 * re-exported). The whole token system keys off a `.dark` class, so the toggle
 * is hand-wired to toggle `document.documentElement.classList`.
 *
 * FRICTION (Minor, docs-gap): `SearchInput` is documented as the docs search box,
 * but it has no built-in ⌘K wiring and no built-in label — you must add the
 * keydown listener + an aria-label yourself. `Drawer` and `Sheet` both exist with
 * `side="left"`; the docs don't say which is canonical for a nav drawer (Sheet is
 * Radix-Dialog-based with a built-in Title/close, so I use Sheet).
 */
export function TopBar({ commandGroups }: { commandGroups: CommandGroups }) {
  const [paletteOpen, setPaletteOpen] = React.useState(false);
  const [drawerOpen, setDrawerOpen] = React.useState(false);
  const [isDark, setIsDark] = React.useState(false);

  // ⌘K / Ctrl-K opens the command palette (hand-wired — not provided by SearchInput).
  React.useEffect(() => {
    const onKey = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.key.toLowerCase() === "k") {
        e.preventDefault();
        setPaletteOpen((o) => !o);
      }
    };
    window.addEventListener("keydown", onKey);
    return () => window.removeEventListener("keydown", onKey);
  }, []);

  // Hand-wired theme toggle (no component / provider re-exported by the package).
  // Subscribe to the <html> class as an external system (keeps the button in
  // sync no matter who toggles `.dark`) instead of a synchronous setState.
  React.useEffect(() => {
    const root = document.documentElement;
    const sync = () => setIsDark(root.classList.contains("dark"));
    sync();
    const mo = new MutationObserver(sync);
    mo.observe(root, { attributes: true, attributeFilter: ["class"] });
    return () => mo.disconnect();
  }, []);
  const toggleTheme = () => {
    const root = document.documentElement;
    root.classList.toggle("dark", !root.classList.contains("dark"));
  };

  return (
    <Header className="sticky top-0 z-40">
      <HeaderBrand className="gap-2">
        {/* Mobile hamburger — opens the sidebar Sheet. Real <button> w/ aria. */}
        <button
          type="button"
          onClick={() => setDrawerOpen(true)}
          aria-label="ナビゲーションメニューを開く"
          aria-expanded={drawerOpen}
          aria-controls="docs-mobile-nav"
          className="-ml-1 inline-flex h-9 w-9 items-center justify-center rounded-md text-muted-foreground transition-colors hover:bg-muted hover:text-foreground focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring md:hidden"
        >
          <IconMenu2 className="h-5 w-5" />
        </button>
        <a href="#" className="flex items-center gap-2 font-semibold tracking-tight">
          <span className="grid h-6 w-6 place-items-center rounded-md bg-primary-strong text-primary-strong-foreground">
            <IconRocket className="h-3.5 w-3.5" />
          </span>
          Driftwood
        </a>
      </HeaderBrand>

      <HeaderNav className="hidden md:flex" aria-label="メインメニュー">
        {topNav.map((link, i) => (
          <HeaderNavLink key={link.label} href={link.href} active={i === 0}>
            {link.label}
          </HeaderNavLink>
        ))}
      </HeaderNav>

      <HeaderActions>
        {/* Desktop: a ⌘K trigger styled like a search box. */}
        <button
          type="button"
          onClick={() => setPaletteOpen(true)}
          className="hidden h-9 items-center gap-2 rounded-md border border-input bg-transparent pl-3 pr-2 text-sm text-muted-foreground transition-colors hover:bg-muted sm:inline-flex"
          aria-label="ドキュメントを検索（Command-K）"
        >
          <span>検索…</span>
          <Kbd>⌘K</Kbd>
        </button>

        <Button
          variant="ghost"
          size="icon"
          aria-label="ダークモードを切り替え"
          onClick={toggleTheme}
        >
          {isDark ? <IconSun className="h-4 w-4" /> : <IconMoon className="h-4 w-4" />}
        </Button>

        <Button asChild variant="ghost" size="icon" aria-label="GitHubリポジトリ">
          <a href="https://github.com" target="_blank" rel="noreferrer">
            <IconBrandGithub className="h-4 w-4" />
          </a>
        </Button>
      </HeaderActions>

      {/* Mobile search lives inside the drawer header for reachability. */}
      <CommandPalette
        groups={commandGroups}
        open={paletteOpen}
        onOpenChange={setPaletteOpen}
        placeholder="ドキュメント・コンポーネント・ガイドを検索…"
      />

      <Sheet open={drawerOpen} onOpenChange={setDrawerOpen}>
        <SheetContent side="left" className="w-[280px] p-0">
          <SheetHeader className="border-b px-4 py-3 text-left">
            <SheetTitle className="flex items-center gap-2">
              <IconRocket className="h-4 w-4" /> Driftwood
            </SheetTitle>
            {/*
              FRICTION (Minor, a11y/DX): Radix logs "Missing Description or
              aria-describedby for DialogContent" when Sheet has no description.
              gunjo's Sheet exports SheetDescription but neither auto-provides one
              nor offers a prop to suppress the warning, so every Sheet consumer
              must remember to add this (here visually hidden) to clear console noise.
            */}
            <SheetDescription className="sr-only">
              ドキュメントのナビゲーション
            </SheetDescription>
          </SheetHeader>
          <div id="docs-mobile-nav" className="flex flex-col gap-4 overflow-y-auto p-4">
            <SearchInput aria-label="ドキュメントを検索" placeholder="検索…" />
            <SidebarNav idPrefix="m-" onNavigate={() => setDrawerOpen(false)} />
          </div>
        </SheetContent>
      </Sheet>
    </Header>
  );
}

// Re-derive the CommandPalette group type from its public prop shape.
type CommandGroups = React.ComponentProps<typeof CommandPalette>["groups"];

// Helper data for the icons used in the palette, kept here for colocation.
export const paletteIcons = {
  book: <IconBook className="h-4 w-4" />,
  download: <IconDownload className="h-4 w-4" />,
  rocket: <IconRocket className="h-4 w-4" />,
};
